#!/usr/bin/env python3\n\"\"\"\nUtility Functions Library\nShared functions used across analysis pipeline\n\nModules:\n  - Data loading and preparation\n  - Feature engineering\n  - Model evaluation\n  - Results export\n  - Logging and timing\n\nAuthor: Replication Project\nDate: 2026-04-29\n\"\"\"\n\nimport numpy as np\nimport pandas as pd\nfrom sklearn.preprocessing import StandardScaler\nfrom sklearn.model_selection import train_test_split\nfrom sklearn.metrics import mean_squared_error, mean_absolute_error, r2_score\nimport json\nimport pickle\nfrom typing import Tuple, Dict, Any, Optional\nfrom pathlib import Path\nimport logging\n\nlogger = logging.getLogger(__name__)\n\n\n# ============================================================================\n# DATA LOADING AND PREPARATION\n# ============================================================================\n\ndef load_simulated_data(filepath: str = 'data/raw/simulated_data.txt') -> pd.DataFrame:\n    \"\"\"\n    Load simulated data from CSV file with error handling.\n    \n    Parameters\n    ----------\n    filepath : str\n        Path to simulated data file\n    \n    Returns\n    -------\n    pd.DataFrame\n        Loaded dataframe with 778 columns\n    \n    Raises\n    ------\n    FileNotFoundError\n        If file doesn't exist\n    ValueError\n        If data structure is invalid\n    \"\"\"\n    logger.info(f\"Loading data from {filepath}...\")\n    \n    if not Path(filepath).exists():\n        raise FileNotFoundError(f\"Data file not found: {filepath}\")\n    \n    df = pd.read_csv(filepath)\n    \n    # Basic validation\n    if df.shape[1] != 778:\n        logger.warning(f\"Expected 778 columns, got {df.shape[1]}\")\n    \n    logger.info(f\"✓ Data loaded: shape {df.shape}\")\n    return df\n\n\ndef extract_components(df: pd.DataFrame, S: int = 375, A: int = 25) -> Tuple[\n    pd.DataFrame, pd.Series, pd.DataFrame, np.ndarray, np.ndarray\n]:\n    \"\"\"\n    Extract state, action, outcome, and identifiers from data.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        Full simulated data\n    S : int\n        Number of state dimensions\n    A : int\n        Number of actions\n    \n    Returns\n    -------\n    Tuple of:\n        - state_features: DataFrame of state variables (s1-s375)\n        - actions: Series of action indices (1-25)\n        - next_state_features: DataFrame of next-state variables\n        - identifiers: array of (buyer_id, receive_time_id)\n        - outcomes: Series of outcome values\n    \"\"\"\n    logger.info(\"Extracting components from data...\")\n    \n    # States: columns s1 to s375\n    state_cols = [f's{i}' for i in range(1, S + 1)]\n    states = df[state_cols].copy()\n    \n    # Actions: one-hot encoded, extract argmax\n    action_cols = [f'a{i}' for i in range(1, A + 1)]\n    actions = df[action_cols].idxmax(axis=1)\n    actions = actions.str.replace('a', '').astype(int)\n    \n    # Next states\n    next_state_cols = [f'ns{i}' for i in range(1, S + 1)]\n    next_states = df[next_state_cols].copy()\n    \n    # Identifiers\n    identifiers = df[['buyer_id', 'receive_time_id']].values\n    \n    # Outcomes\n    outcomes = df['div_pay_amt_fillna'].copy()\n    \n    logger.info(f\"  States: {states.shape}\")\n    logger.info(f\"  Actions: {actions.shape} (unique: {actions.nunique()})\")\n    logger.info(f\"  Outcomes: {outcomes.shape}\")\n    \n    return states, actions, next_states, identifiers, outcomes\n\n\ndef prepare_features(\n    df: pd.DataFrame,\n    S: int = 375,\n    A: int = 25,\n    standardize: bool = False\n) -> Tuple[np.ndarray, np.ndarray, np.ndarray]:\n    \"\"\"\n    Prepare features for ML models: combine states and action dummies.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        Full simulated data\n    S : int\n        Number of state dimensions\n    A : int\n        Number of actions\n    standardize : bool\n        Whether to standardize features\n    \n    Returns\n    -------\n    Tuple of:\n        - X: Feature matrix (n_samples, S+A)\n        - y: Target vector (n_samples,)\n        - feature_names: List of feature names\n    \"\"\"\n    logger.info(\"Preparing features for ML models...\")\n    \n    # Extract states and action dummies\n    state_cols = [f's{i}' for i in range(1, S + 1)]\n    action_cols = [f'a{i}' for i in range(1, A + 1)]\n    \n    X = df[state_cols + action_cols].values.astype(np.float32)\n    y = df['div_pay_amt_fillna'].values.astype(np.float32)\n    feature_names = state_cols + action_cols\n    \n    # Standardize if requested\n    if standardize:\n        scaler = StandardScaler()\n        X = scaler.fit_transform(X)\n        logger.info(\"  Features standardized\")\n    \n    logger.info(f\"  X shape: {X.shape}\")\n    logger.info(f\"  y shape: {y.shape}\")\n    \n    return X, y, feature_names\n\n\ndef train_test_split_chronological(\n    X: np.ndarray,\n    y: np.ndarray,\n    identifiers: np.ndarray,\n    train_ratio: float = 0.7,\n    random_state: int = 42\n) -> Tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray]:\n    \"\"\"\n    Chronological train-test split within each buyer trajectory.\n    \n    Split each buyer's trajectory into train (first 70%) and test (last 30%)\n    to respect temporal ordering.\n    \n    Parameters\n    ----------\n    X : np.ndarray\n        Feature matrix\n    y : np.ndarray\n        Target vector\n    identifiers : np.ndarray\n        Array of (buyer_id, receive_time_id)\n    train_ratio : float\n        Proportion of data for training\n    random_state : int\n        Random seed\n    \n    Returns\n    -------\n    Tuple of:\n        - X_train, X_test: Feature matrices\n        - y_train, y_test: Target vectors\n    \"\"\"\n    logger.info(f\"Performing chronological train-test split ({train_ratio*100:.0f}/{(1-train_ratio)*100:.0f})...\")\n    \n    df_temp = pd.DataFrame({\n        'buyer_id': identifiers[:, 0],\n        'receive_time_id': identifiers[:, 1],\n        'X_idx': np.arange(len(X))\n    })\n    \n    # For each buyer, split at 70% mark\n    train_indices = []\n    test_indices = []\n    \n    for buyer_id in df_temp['buyer_id'].unique():\n        buyer_data = df_temp[df_temp['buyer_id'] == buyer_id]\n        n_buyer_samples = len(buyer_data)\n        split_point = int(n_buyer_samples * train_ratio)\n        \n        buyer_indices = buyer_data['X_idx'].values\n        train_indices.extend(buyer_indices[:split_point])\n        test_indices.extend(buyer_indices[split_point:])\n    \n    train_indices = np.array(train_indices)\n    test_indices = np.array(test_indices)\n    \n    X_train, X_test = X[train_indices], X[test_indices]\n    y_train, y_test = y[train_indices], y[test_indices]\n    \n    logger.info(f\"  Train set: {X_train.shape[0]} samples\")\n    logger.info(f\"  Test set: {X_test.shape[0]} samples\")\n    \n    return X_train, X_test, y_train, y_test\n\n\ndef standardize_features(\n    X_train: np.ndarray,\n    X_test: np.ndarray\n) -> Tuple[np.ndarray, np.ndarray, StandardScaler]:\n    \"\"\"\n    Standardize features using training data statistics.\n    \n    Parameters\n    ----------\n    X_train : np.ndarray\n        Training features\n    X_test : np.ndarray\n        Test features\n    \n    Returns\n    -------\n    Tuple of:\n        - X_train_scaled: Standardized training features\n        - X_test_scaled: Standardized test features\n        - scaler: Fitted StandardScaler object\n    \"\"\"\n    logger.info(\"Standardizing features...\")\n    \n    scaler = StandardScaler()\n    X_train_scaled = scaler.fit_transform(X_train)\n    X_test_scaled = scaler.transform(X_test)\n    \n    logger.info(f\"  X_train mean: {X_train_scaled.mean():.4f}, std: {X_train_scaled.std():.4f}\")\n    logger.info(f\"  X_test mean: {X_test_scaled.mean():.4f}, std: {X_test_scaled.std():.4f}\")\n    \n    return X_train_scaled, X_test_scaled, scaler\n\n\n# ============================================================================\n# MODEL EVALUATION\n# ============================================================================\n\ndef calculate_metrics(y_true: np.ndarray, y_pred: np.ndarray) -> Dict[str, float]:\n    \"\"\"\n    Calculate standard regression metrics.\n    \n    Parameters\n    ----------\n    y_true : np.ndarray\n        True values\n    y_pred : np.ndarray\n        Predicted values\n    \n    Returns\n    -------\n    Dict[str, float]\n        Dictionary with RMSE, MAE, R2, MAPE\n    \"\"\"\n    rmse = np.sqrt(mean_squared_error(y_true, y_pred))\n    mae = mean_absolute_error(y_true, y_pred)\n    r2 = r2_score(y_true, y_pred)\n    \n    # MAPE (Mean Absolute Percentage Error)\n    # Handle division by zero\n    mask = y_true != 0\n    if mask.sum() > 0:\n        mape = np.mean(np.abs((y_true[mask] - y_pred[mask]) / y_true[mask])) * 100\n    else:\n        mape = np.nan\n    \n    return {\n        'rmse': float(rmse),\n        'mae': float(mae),\n        'r2': float(r2),\n        'mape': float(mape) if not np.isnan(mape) else None\n    }\n\n\ndef compare_models(results: Dict[str, Dict[str, float]]) -> pd.DataFrame:\n    \"\"\"\n    Create comparison table of model results.\n    \n    Parameters\n    ----------\n    results : Dict[str, Dict[str, float]]\n        Dictionary mapping model names to metric dictionaries\n    \n    Returns\n    -------\n    pd.DataFrame\n        Comparison table\n    \"\"\"\n    df_comparison = pd.DataFrame(results).T\n    df_comparison = df_comparison.round(4)\n    return df_comparison\n\n\n# ============================================================================\n# RESULTS EXPORT\n# ============================================================================\n\ndef save_results(\n    results: Dict[str, Any],\n    output_path: str,\n    format: str = 'csv'\n) -> None:\n    \"\"\"\n    Save results to file (CSV, JSON, or pickle).\n    \n    Parameters\n    ----------\n    results : Dict\n        Results dictionary or DataFrame\n    output_path : str\n        Path to save results\n    format : str\n        Format: 'csv', 'json', or 'pickle'\n    \"\"\"\n    Path(output_path).parent.mkdir(parents=True, exist_ok=True)\n    \n    logger.info(f\"Saving results to {output_path} ({format})...\")\n    \n    if format == 'csv':\n        if isinstance(results, pd.DataFrame):\n            results.to_csv(output_path, index=False)\n        else:\n            pd.DataFrame(results).to_csv(output_path, index=False)\n    \n    elif format == 'json':\n        with open(output_path, 'w') as f:\n            json.dump(results, f, indent=2)\n    \n    elif format == 'pickle':\n        with open(output_path, 'wb') as f:\n            pickle.dump(results, f)\n    \n    logger.info(f\"  ✓ Results saved\")\n\n\n# ============================================================================\n# BEHAVIOR POLICY ESTIMATION\n# ============================================================================\n\ndef estimate_behavior_policy(\n    df: pd.DataFrame,\n    A: int = 25,\n    S: int = 375\n) -> Dict[Tuple[int, ...], np.ndarray]:\n    \"\"\"\n    Estimate behavior policy from historical action distribution.\n    \n    Computes P(a|s) for all observed state-action pairs.\n    Uses action frequency as empirical probability.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        Full data\n    A : int\n        Number of actions\n    S : int\n        Number of states\n    \n    Returns\n    -------\n    Dict\n        Mapping from state (tuple) to action probability vector\n    \"\"\"\n    logger.info(\"Estimating behavior policy...\")\n    \n    # Global action frequency (simple approach)\n    action_cols = [f'a{i}' for i in range(1, A + 1)]\n    action_freq = df[action_cols].sum() / len(df)\n    behavior_policy_global = action_freq.values\n    \n    logger.info(f\"  Global action probabilities: {behavior_policy_global.round(4)}\")\n    \n    return behavior_policy_global\n\n\n# ============================================================================\n# LOGGING AND TIMING\n# ============================================================================\n\ndef setup_logging(log_file: str = 'logs/replication.log'):\n    \"\"\"\n    Setup logging configuration.\n    \n    Parameters\n    ----------\n    log_file : str\n        Path to log file\n    \"\"\"\n    Path(log_file).parent.mkdir(parents=True, exist_ok=True)\n    \n    logging.basicConfig(\n        level=logging.INFO,\n        format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',\n        handlers=[\n            logging.FileHandler(log_file),\n            logging.StreamHandler()\n        ]\n    )\n\n\nclass Timer:\n    \"\"\"\n    Context manager for timing code blocks.\n    \n    Usage:\n        with Timer(\"Model training\"):\n            model.fit(X_train, y_train)\n    \"\"\"\n    \n    def __init__(self, name: str = \"Operation\"):\n        self.name = name\n        self.start_time = None\n    \n    def __enter__(self):\n        self.start_time = pd.Timestamp.now()\n        logger.info(f\"[TIMER] Starting: {self.name}\")\n        return self\n    \n    def __exit__(self, *args):\n        elapsed = (pd.Timestamp.now() - self.start_time).total_seconds()\n        logger.info(f\"[TIMER] Completed: {self.name} ({elapsed:.2f}s)\")\n\n\n# ============================================================================\n# DATA STRUCTURE HELPERS\n# ============================================================================\n\ndef print_data_info(df: pd.DataFrame):\n    \"\"\"\n    Print comprehensive data information.\n    \n    Parameters\n    ----------\n    df : pd.DataFrame\n        Data to summarize\n    \"\"\"\n    logger.info(\"\\n\" + \"=\"*80)\n    logger.info(\"DATA INFORMATION\")\n    logger.info(\"=\"*80)\n    logger.info(f\"Shape: {df.shape}\")\n    logger.info(f\"\\nColumns ({df.shape[1]}):\")\n    \n    # Group columns by type\n    state_cols = [col for col in df.columns if col.startswith('s') and not col.startswith('ns')]\n    action_cols = [col for col in df.columns if col.startswith('a')]\n    next_state_cols = [col for col in df.columns if col.startswith('ns')]\n    \n    logger.info(f\"  - Identifiers: buyer_id, receive_time_id\")\n    logger.info(f\"  - State features: {len(state_cols)} (s1-s{len(state_cols)})\")\n    logger.info(f\"  - Actions: {len(action_cols)} (a1-a{len(action_cols)})\")\n    logger.info(f\"  - Next states: {len(next_state_cols)} (ns1-ns{len(next_state_cols)})\")\n    logger.info(f\"  - Outcome: div_pay_amt_fillna\")\n    \n    logger.info(f\"\\nData types:\\n{df.dtypes.value_counts()}\")\n    logger.info(f\"\\nMissing values:\\n{df.isnull().sum().sum()} total\")\n    \n    logger.info(\"=\"*80 + \"\\n\")\n\n\nif __name__ == '__main__':\n    # Example usage\n    setup_logging()\n    logger = logging.getLogger(__name__)\n    \n    df = load_simulated_data()\n    print_data_info(df)\n    \n    X, y, feature_names = prepare_features(df)\n    logger.info(f\"Features prepared: {X.shape}\")\n"